     5→//! Parade command - Display comprehensive Heat status for project review
     6→//!
     7→//! Implements both heat view (Firemark) and pace view (Coronet).
     8→
     9→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    10→use crate::jjrf_favor::jjrf_Coronet as Coronet;
    11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_Heat as Heat, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
    13→use crate::jjrq_query::{jjrq_files_for_pace, jjrq_file_touches_for_heat};
    14→use std::collections::BTreeMap;
    15→use std::fs;
    16→
    17→/// Arguments for jjx_parade command
    18→#[derive(clap::Args, Debug)]
    19→pub struct jjrpd_ParadeArgs {
    20→    /// Path to the Gallops JSON file
    21→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    22→    pub file: std::path::PathBuf,
    23→
    24→    /// Target: Firemark (heat view) or Coronet (pace view). If omitted, uses first racing heat.
    25→    pub target: Option<String>,
    26→
    27→    /// Show paddock and full specs (heat mode only)
    28→    #[arg(long)]
    29→    pub full: bool,
    30→
    31→    /// Show only remaining paces (exclude complete/abandoned)
    32→    #[arg(long)]
    33→    pub remaining: bool,
    34→}
    35→
    36→/// Run the parade command - display comprehensive Heat status
    37→pub fn jjrpd_run_parade(args: jjrpd_ParadeArgs) -> i32 {
    38→    let gallops = match Gallops::jjrg_load(&args.file) {
    39→        Ok(g) => g,
    40→        Err(e) => {
    41→            eprintln!("jjx_parade: error: {}", e);
    42→            return 1;
    43→        }
    44→    };
    45→
    46→    // Resolve target: use provided value or auto-select first racing heat
    47→    let target = match args.target {
    48→        Some(t) => t,
    49→        None => {
    50→            // Load gallops to resolve default heat
    51→            match zjjrpd_resolve_default_heat(&gallops) {
    52→                Ok(fm) => fm,
    53→                Err(e) => {
    54→                    eprintln!("jjx_parade: error: {}", e);
    55→                    return 1;
    56→                }
    57→            }
    58→        }
    59→    };
    60→
    61→    // Determine target type by length
    62→    let target_str = target.strip_prefix('₢').or_else(|| target.strip_prefix('₣')).unwrap_or(&target);
    63→
    64→    if target_str.len() == 5 {
    65→        // Coronet - pace view
    66→        let coronet = match Coronet::jjrf_parse(&target) {
    67→            Ok(c) => c,
    68→            Err(e) => {
    69→                eprintln!("jjx_parade: error: {}", e);
    70→                return 1;
    71→            }
    72→        };
    73→
    74→        // Extract parent firemark
    75→        let firemark = coronet.jjrf_parent_firemark();
    76→        let heat_key = firemark.jjrf_display();
    77→        let heat = match gallops.heats.get(&heat_key) {
    78→            Some(h) => h,
    79→            None => {
    80→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
    81→                return 1;
    82→            }
    83→        };
    84→
    85→        // Find pace
    86→        let coronet_key = coronet.jjrf_display();
    87→        let pace = match heat.paces.get(&coronet_key) {
    88→            Some(p) => p,
    89→            None => {
    90→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
    91→                return 1;
    92→            }
    93→        };
    94→
    95→        // Display tack history - iterate in reverse order (oldest first)
    96→        if !pace.tacks.is_empty() {
    97→            // Print header with current state from tacks[0]
    98→            let current_tack = &pace.tacks[0];
    99→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
   100→            println!("Heat: {}", heat_key);
   101→
   102→            // Show work files touched by this pace's commits
   103→            match jjrq_files_for_pace(firemark.jjrf_as_str(), &coronet_key) {
   104→                Ok(files) if !files.is_empty() => {
   105→                    println!("Work files: {}", files.join(", "));
   106→                }
   107→                _ => {}
   108→            }
   109→            println!();
   110→
   111→            // Iterate tacks in reverse order (oldest first)
   112→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   113→                let state_str = zjjrpd_pace_state_str(&tack.state);
   114→                let basis_str = if tack.basis == "0000000" {
   115→                    "(no basis)".to_string()
   116→                } else {
   117→                    tack.basis.clone()
   118→                };
   119→
   120→                println!("[{}] {} (basis: {})", index, state_str, basis_str);
   121→                println!("    Silks: {}", tack.silks);
   122→                if let Some(ref direction) = tack.direction {
   123→                    println!("    Direction: {}", direction);
   124→                }
   125→                println!();
   126→                // Indent spec text
   127→                for line in tack.text.lines() {
   128→                    println!("    {}", line);
   129→                }
   130→                println!();
   131→            }
   132→        }
   133→    } else if target_str.len() == 2 {
   134→        // Firemark - heat view
   135→        let firemark = match Firemark::jjrf_parse(&target) {
   136→            Ok(fm) => fm,
   137→            Err(e) => {
   138→                eprintln!("jjx_parade: error: {}", e);
   139→                return 1;
   140→            }
   141→        };
   142→
   143→        let heat_key = firemark.jjrf_display();
   144→        let heat = match gallops.heats.get(&heat_key) {
   145→            Some(h) => h,
   146→            None => {
   147→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   148→                return 1;
   149→            }
   150→        };
   151→
   152→        if args.full {
   153→            // Full view: paddock + all specs
   154→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   155→                Ok(content) => content,
   156→                Err(e) => {
   157→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   158→                    return 1;
   159→                }
   160→            };
   161→
   162→            let status_str = match heat.status {
   163→                HeatStatus::Racing => "racing",
   164→                HeatStatus::Stabled => "stabled",
   165→                HeatStatus::Retired => "retired",
   166→            };
   167→
   168→            println!("Heat: {} ({})", heat.silks, heat_key);
   169→            println!("Status: {}", status_str);
   170→            println!("Created: {}", heat.creation_time);
   171→            println!();
   172→            println!("## Paddock");
   173→            println!();
   174→            println!("{}", paddock_content);
   175→            println!();
   176→            println!("## Paces");
   177→            println!();
   178→
   179→            for coronet_key in &heat.order {
   180→                if let Some(pace) = heat.paces.get(coronet_key) {
   181→                    if let Some(tack) = pace.tacks.first() {
   182→                        // Skip complete/abandoned if --remaining
   183→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   184→                            continue;
   185→                        }
   186→                        let state_str = zjjrpd_pace_state_str(&tack.state);
   187→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   188→                        println!();
   189→                        println!("{}", tack.text);
   190→                        if let Some(ref direction) = tack.direction {
   191→                            println!();
   192→                            println!("**Direction:** {}", direction);
   193→                        }
   194→                        println!();
   195→                    }
   196→                }
   197→            }
   198→        } else {
   199→            // List view: numbered paces
   200→            // If --remaining, output markdown format
   201→            if args.remaining {
   202→                let mut complete_count = 0;
   203→                let mut abandoned_count = 0;
   204→                let mut rough_count = 0;
   205→                let mut bridled_count = 0;
   206→                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
   207→                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
   208→
   209→                for coronet_key in &heat.order {
   210→                    if let Some(pace) = heat.paces.get(coronet_key) {
   211→                        if let Some(tack) = pace.tacks.first() {
   212→                            match tack.state {
   213→                                PaceState::Complete => complete_count += 1,
   214→                                PaceState::Abandoned => abandoned_count += 1,
   215→                                PaceState::Rough => {
   216→                                    rough_count += 1;
   217→                                    remaining_paces.push((coronet_key, pace));
   218→                                    if first_remaining_pace.is_none() {
   219→                                        first_remaining_pace = Some((coronet_key, pace));
   220→                                    }
   221→                                }
   222→                                PaceState::Bridled => {
   223→                                    bridled_count += 1;
   224→                                    remaining_paces.push((coronet_key, pace));
   225→                                    if first_remaining_pace.is_none() {
   226→                                        first_remaining_pace = Some((coronet_key, pace));
   227→                                    }
   228→                                }
   229→                            }
   230→                        }
   231→                    }
   232→                }
   233→
   234→                let status_str = match heat.status {
   235→                    HeatStatus::Racing => "racing",
   236→                    HeatStatus::Stabled => "stabled",
   237→                    HeatStatus::Retired => "retired",
   238→                };
   239→
   240→                let remaining_count = rough_count + bridled_count;
   241→
   242→                // Header line with heat info
   243→                println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   244→                println!("Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
   245→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
   246→                println!();
   247→
   248→                // Table with remaining paces
   249→                if !remaining_paces.is_empty() {
   250→                    // Set up table with column definitions
   251→                    let mut table = jjrp_Table::jjrp_new(vec![
   252→                        jjrp_Column::new("No", jjrp_Align::Right),
   253→                        jjrp_Column::new("State", jjrp_Align::Left),
   254→                        jjrp_Column::new("Pace", jjrp_Align::Left),
   255→                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   256→                    ]);
   257→
   258→                    // Measure all rows to compute column widths
   259→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   260→                        if let Some(tack) = pace.tacks.first() {
   261→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   262→                            table.jjrp_measure(&[
   263→                                &(idx + 1).to_string(),
   264→                                state_str,
   265→                                &tack.silks,
   266→                                coronet_key,
   267→                            ]);
   268→                        }
   269→                    }
   270→
   271→                    // Print header and separator
   272→                    table.jjrp_print_header();
   273→                    table.jjrp_print_separator();
   274→
   275→                    // Print data rows
   276→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   277→                        if let Some(tack) = pace.tacks.first() {
   278→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   279→                            table.jjrp_print_row(&[
   280→                                &(idx + 1).to_string(),
   281→                                state_str,
   282→                                &tack.silks,
   283→                                coronet_key,
   284→                            ]);
   285→                        }
   286→                    }
   287→                    println!();
   288→                }
   289→
   290→                // Next up callout
   291→                if let Some((coronet_key, pace)) = first_remaining_pace {
   292→                    if let Some(tack) = pace.tacks.first() {
   293→                        let state_str = zjjrpd_pace_state_str(&tack.state);
   294→                        println!("Next: {} ({}) [{}]", tack.silks, coronet_key, state_str);
   295→                    }
   296→                }
   297→            } else {
   298→                // Column-justified list view (all paces)
   299→                // Set up table with column definitions
   300→                let mut table = jjrp_Table::jjrp_new(vec![
   301→                    jjrp_Column::new("No", jjrp_Align::Right),
   302→                    jjrp_Column::new("State", jjrp_Align::Left),
   303→                    jjrp_Column::new("Pace", jjrp_Align::Left),
   304→                    jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   305→                ]);
   306→
   307→                // Measure all rows to compute column widths
   308→                let mut num = 0;
   309→                for coronet_key in &heat.order {
   310→                    if let Some(pace) = heat.paces.get(coronet_key) {
   311→                        if let Some(tack) = pace.tacks.first() {
   312→                            num += 1;
   313→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   314→                            table.jjrp_measure(&[
   315→                                &num.to_string(),
   316→                                state_str,
   317→                                &tack.silks,
   318→                                coronet_key,
   319→                            ]);
   320→                        }
   321→                    }
   322→                }
   323→
   324→                // Print header and separator
   325→                table.jjrp_print_header();
   326→                table.jjrp_print_separator();
   327→
   328→                // Print data rows
   329→                let mut num = 0;
   330→                for coronet_key in &heat.order {
   331→                    if let Some(pace) = heat.paces.get(coronet_key) {
   332→                        if let Some(tack) = pace.tacks.first() {
   333→                            num += 1;
   334→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   335→                            table.jjrp_print_row(&[
   336→                                &num.to_string(),
   337→                                state_str,
   338→                                &tack.silks,
   339→                                coronet_key,
   340→                            ]);
   341→                        }
   342→                    }
   343→                }
   344→            }
   345→        }
   346→
   347→        // Always show file-touch bitmap after pace listing
   348→        zjjrpd_print_file_bitmap(&firemark, heat);
   349→    } else {
   350→        eprintln!("jjx_parade: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", target_str.len());
   351→        return 1;
   352→    }
   353→
   354→    0
   355→}
   356→
   357→/// Build and print the file-touch bitmap for a heat.
   358→///
   359→/// Uses shared query routines from jjrq_query to get file touches,
   360→/// then formats as a bitmap with columns per pace and rows per file,
   361→/// grouped by identical touch patterns.
   362→fn zjjrpd_print_file_bitmap(firemark: &Firemark, heat: &Heat) {
   363→    let touches = match jjrq_file_touches_for_heat(firemark.jjrf_as_str()) {
   364→        Ok(t) => t,
   365→        Err(e) => {
   366→            eprintln!("jjx_parade: error getting file touches: {}", e);
   367→            return;
   368→        }
   369→    };
   370→
   371→    let has_heat_level = !touches.heat_files.is_empty();
   372→
   373→    // Build pace columns: only paces with commits, in heat order
   374→    let mut pace_columns: Vec<(char, String, String)> = Vec::new();
   375→    for coronet_key in &heat.order {
   376→        if !touches.coronets_with_commits.contains(coronet_key) {
   377→            continue;
   378→        }
   379→        if let Some(pace) = heat.paces.get(coronet_key) {
   380→            if let Some(tack) = pace.tacks.first() {
   381→                let raw = coronet_key.strip_prefix('₢').unwrap_or(coronet_key);
   382→                if let Some(ch) = raw.chars().last() {
   383→                    pace_columns.push((ch, coronet_key.clone(), tack.silks.clone()));
   384→                }
   385→            }
   386→        }
   387→    }
   388→
   389→    // Map coronet_display -> column index
   390→    let mut coronet_to_col: BTreeMap<String, usize> = BTreeMap::new();
   391→    for (idx, (_, coronet_display, _)) in pace_columns.iter().enumerate() {
   392→        coronet_to_col.insert(coronet_display.clone(), idx);
   393→    }
   394→
   395→    let heat_col_idx = pace_columns.len();
   396→    let total_cols = if has_heat_level { heat_col_idx + 1 } else { heat_col_idx };
   397→
   398→    // Build file -> touch vector from the shared query result
   399→    let mut file_touches_map: BTreeMap<String, Vec<bool>> = BTreeMap::new();
   400→
   401→    for (coronet, files) in &touches.pace_files {
   402→        if let Some(&col_idx) = coronet_to_col.get(coronet) {
   403→            for filename in files {
   404→                let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
   405→                if col_idx < row.len() {
   406→                    row[col_idx] = true;
   407→                }
   408→            }
   409→        }
   410→    }
   411→
   412→    if has_heat_level {
   413→        for filename in &touches.heat_files {
   414→            let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
   415→            if heat_col_idx < row.len() {
   416→                row[heat_col_idx] = true;
   417→            }
   418→        }
   419→    }
   420→
   421→    if file_touches_map.is_empty() {
   422→        println!("File-touch bitmap: (no work file changes)");
   423→        return;
   424→    }
   425→
   426→    // Group files by identical touch pattern
   427→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
   428→    for (filename, pattern) in &file_touches_map {
   429→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
   430→    }
   431→
   432→    for files in pattern_groups.values_mut() {
   433→        files.sort();
   434→    }
   435→
   436→    // Print header
   437→    println!("File-touch bitmap (x = pace commit touched file):");
   438→    println!();
   439→
   440→    // Print vertical legend
   441→    for (i, (ch, _coronet, silks)) in pace_columns.iter().enumerate() {
   442→        println!("  {} {} {}", i + 1, ch, silks);
   443→    }
   444→    if has_heat_level {
   445→        println!("  {} * heat-level", pace_columns.len() + 1);
   446→    }
   447→    println!();
   448→
   449→    // Print column header line (terminal chars aligned with bitmap positions)
   450→    let mut header_chars: Vec<char> = pace_columns.iter().map(|(ch, _, _)| *ch).collect();
   451→    if has_heat_level {
   452→        header_chars.push('*');
   453→    }
   454→    let header_line: String = header_chars.iter().collect();
   455→    println!("{}", header_line);
   456→
   457→    // Sort patterns: more touches first, then lexicographic
   458→    let mut sorted_patterns: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
   459→    sorted_patterns.sort_by(|(pat_a, _), (pat_b, _)| {
   460→        let count_a: usize = pat_a.iter().filter(|&&b| b).count();
   461→        let count_b: usize = pat_b.iter().filter(|&&b| b).count();
   462→        count_b.cmp(&count_a).then_with(|| pat_a.cmp(pat_b))
   463→    });
   464→
   465→    for (pattern, files) in &sorted_patterns {
   466→        let bitmap: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
   467→        println!("{} {}", bitmap, files.join(", "));
   468→    }
   469→}
   470→
   471→/// Helper to convert PaceState to display string
   472→pub(crate) fn zjjrpd_pace_state_str(state: &PaceState) -> &'static str {
   473→    match state {
   474→        PaceState::Rough => "rough",
   475→        PaceState::Bridled => "bridled",
   476→        PaceState::Complete => "complete",
   477→        PaceState::Abandoned => "abandoned",
   478→    }
   479→}
   480→
   481→/// Resolve the default heat (first racing heat) when no target is specified
   482→pub(crate) fn zjjrpd_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
   483→    for (heat_key, heat) in &gallops.heats {
   484→        if heat.status == HeatStatus::Racing {
   485→            return Ok(heat_key.clone());
   486→        }
   487→    }
   488→    Err("No racing heats found".to_string())
   489→}
