    23→/// Path prefix for JJ infrastructure files (excluded from work file queries)
    24→const JJRQ_INFRA_PREFIX: &str = ".claude/jjm/";
    25→
    26→/// Resolve the default heat (first racing heat) when no target is specified
    27→pub fn jjrq_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
    28→    for (heat_key, heat) in &gallops.heats {
    29→        if heat.status == HeatStatus::Racing {
    30→            return Ok(heat_key.clone());
    31→        }
    32→    }
    33→    Err("No racing heats found".to_string())
    34→}
