    36→// ============================================================================
    37→// File-touch queries (work files touched by pace commits)
    38→// ============================================================================
    39→
    40→/// Get files changed by a single commit via git diff-tree
    41→pub(crate) fn zjjrq_files_for_commit(sha: &str) -> Vec<String> {
    42→    let output = Command::new("git")
    43→        .args(["diff-tree", "--no-commit-id", "--name-only", "-r", sha])
    44→        .output();
    45→
    46→    match output {
    47→        Ok(out) if out.status.success() => {
    48→            String::from_utf8_lossy(&out.stdout)
    49→                .lines()
    50→                .filter(|l| !l.is_empty())
    51→                .map(|l| l.to_string())
    52→                .collect()
    53→        }
    54→        _ => Vec::new(),
    55→    }
    56→}
    57→
    58→/// Extract bare filename from a path (last component)
    59→pub(crate) fn zjjrq_bare_filename(path: &str) -> String {
    60→    path.rsplit('/').next().unwrap_or(path).to_string()
    61→}
    62→
    63→/// Test whether a file path is JJ infrastructure (excluded from work file results)
    64→pub(crate) fn zjjrq_is_infra_file(path: &str) -> bool {
    65→    path.starts_with(JJRQ_INFRA_PREFIX)
    66→}
    67→
    68→/// Get sorted list of work files touched by a pace's commits.
    69→///
    70→/// Queries steeplechase entries for the heat, filters by coronet,
    71→/// runs `git diff-tree` per commit, and returns unique bare filenames
    72→/// with JJ infrastructure files excluded.
    73→pub fn jjrq_files_for_pace(firemark_raw: &str, coronet_display: &str) -> Result<Vec<String>, String> {
    74→    let rein_args = jjrs_ReinArgs {
    75→        firemark: firemark_raw.to_string(),
    76→        limit: 10000,
    77→    };
    78→
    79→    let entries = jjrs_get_entries(&rein_args)?;
    80→
    81→    let mut files = std::collections::BTreeSet::new();
    82→    for entry in &entries {
    83→        let dominated = match &entry.coronet {
    84→            Some(c) => c == coronet_display,
    85→            None => false,
    86→        };
    87→        if !dominated {
    88→            continue;
    89→        }
    90→        for file_path in zjjrq_files_for_commit(&entry.commit) {
    91→            if !zjjrq_is_infra_file(&file_path) {
    92→                files.insert(zjjrq_bare_filename(&file_path));
    93→            }
    94→        }
    95→    }
    96→
    97→    Ok(files.into_iter().collect())
    98→}
    99→
   100→/// Get all steeplechase entries for a heat with file touch data per commit.
   101→///
   102→/// Returns entries plus a mapping of coronet -> set of bare work filenames.
   103→/// Also returns heat-level (no coronet) work files separately.
   104→/// Used by the file-touch bitmap visualization.
   105→pub fn jjrq_file_touches_for_heat(firemark_raw: &str) -> Result<jjrq_HeatFileTouches, String> {
   106→    let rein_args = jjrs_ReinArgs {
   107→        firemark: firemark_raw.to_string(),
   108→        limit: 10000,
   109→    };
   110→
   111→    let entries = jjrs_get_entries(&rein_args)?;
   112→
   113→    let mut pace_files: std::collections::BTreeMap<String, std::collections::BTreeSet<String>> = std::collections::BTreeMap::new();
   114→    let mut heat_files: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
   115→    let mut coronets_seen: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();
   116→
   117→    for entry in &entries {
   118→        let commit_files: Vec<String> = zjjrq_files_for_commit(&entry.commit)
   119→            .into_iter()
   120→            .filter(|p| !zjjrq_is_infra_file(p))
   121→            .map(|p| zjjrq_bare_filename(&p))
   122→            .collect();
   123→
   124→        if let Some(ref coronet) = entry.coronet {
   125→            coronets_seen.insert(coronet.clone());
   126→            let set = pace_files.entry(coronet.clone()).or_default();
   127→            for f in commit_files {
   128→                set.insert(f);
   129→            }
   130→        } else {
   131→            for f in commit_files {
   132→                heat_files.insert(f);
   133→            }
   134→        }
   135→    }
   136→
   137→    Ok(jjrq_HeatFileTouches {
   138→        pace_files,
   139→        heat_files,
   140→        coronets_with_commits: coronets_seen,
   141→    })
   142→}
   143→
   144→/// Result of querying file touches for an entire heat
   145→pub struct jjrq_HeatFileTouches {
   146→    /// Coronet display string -> set of bare work filenames
   147→    pub pace_files: std::collections::BTreeMap<String, std::collections::BTreeSet<String>>,
   148→    /// Work files from heat-level (no coronet) commits
   149→    pub heat_files: std::collections::BTreeSet<String>,
   150→    /// All coronets that have at least one commit
   151→    pub coronets_with_commits: std::collections::BTreeSet<String>,
   152→}
