     5→//! Favor encoding - Firemark and Coronet identity types
     6→//!
     7→//! Implements base64 encoding/decoding for Job Jockey identity types:
     8→//! - Firemark: Heat identity (2 base64 chars, 0-4095)
     9→//! - Coronet: Pace identity (5 base64 chars, globally unique)
    10→
    11→use serde::{Deserialize, Serialize};
    12→
    13→/// URL-safe base64 charset (RFC 4648 section 5)
    14→pub const JJRF_CHARSET: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_";
    15→
    16→/// Firemark prefix character
    17→pub const JJRF_FIREMARK_PREFIX: char = '₣';
    18→
    19→/// Coronet prefix character
    20→pub const JJRF_CORONET_PREFIX: char = '₢';
    21→
    22→/// Maximum value for Firemark (2^12 - 1)
    23→pub const JJRF_FIREMARK_MAX: u16 = 4095;
    24→
    25→/// Maximum value for Coronet pace index (2^18 - 1)
    26→pub const JJRF_CORONET_PACE_MAX: u32 = 262143;
    27→
    28→/// Look up the position of a character in the charset
    29→pub fn zjjrf_char_to_value(c: char) -> Result<u8, String> {
    30→    let byte = c as u8;
    31→    JJRF_CHARSET
    32→        .iter()
    33→        .position(|&b| b == byte)
    34→        .map(|pos| pos as u8)
    35→        .ok_or_else(|| format!("Invalid base64 character: '{}'", c))
    36→}
    37→
    38→/// Get the character at a given position in the charset
    39→pub fn zjjrf_value_to_char(value: u8) -> char {
    40→    JJRF_CHARSET[value as usize] as char
    41→}
    42→
    43→/// Heat identity - 2 base64 characters encoding 0-4095
    44→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
    45→pub struct jjrf_Firemark(pub String);
    46→
    47→/// Pace identity - 5 base64 characters, globally unique
    48→/// First 2 chars encode parent Heat, last 3 encode pace index (0-262143)
    49→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
    50→pub struct jjrf_Coronet(pub String);
    51→
    52→impl jjrf_Firemark {
    53→    /// Encode an integer (0-4095) as a Firemark
    54→    pub fn jjrf_encode(value: u16) -> Self {
    55→        debug_assert!(value <= JJRF_FIREMARK_MAX, "Firemark value {} exceeds max {}", value, JJRF_FIREMARK_MAX);
    56→        let high = zjjrf_value_to_char((value / 64) as u8);
    57→        let low = zjjrf_value_to_char((value % 64) as u8);
    58→        jjrf_Firemark(format!("{}{}", high, low))
    59→    }
    60→
    61→    /// Decode a Firemark to its integer value
    62→    pub fn jjrf_decode(&self) -> Result<u16, String> {
    63→        let chars: Vec<char> = self.0.chars().collect();
    64→        if chars.len() != 2 {
    65→            return Err(format!("Firemark must be 2 characters, got {}", chars.len()));
    66→        }
    67→        let high = zjjrf_char_to_value(chars[0])? as u16;
    68→        let low = zjjrf_char_to_value(chars[1])? as u16;
    69→        Ok(high * 64 + low)
    70→    }
    71→
    72→    /// Parse a Firemark from string input (with or without prefix)
    73→    pub fn jjrf_parse(input: &str) -> Result<Self, String> {
    74→        let stripped = input.strip_prefix(JJRF_FIREMARK_PREFIX).unwrap_or(input);
    75→        if stripped.len() != 2 {
    76→            return Err(format!(
    77→                "Firemark must be 2 base64 characters (with or without {} prefix), got '{}'",
    78→                JJRF_FIREMARK_PREFIX, input
    79→            ));
    80→        }
    81→        // Validate all characters are in charset
    82→        for c in stripped.chars() {
    83→            zjjrf_char_to_value(c)?;
    84→        }
    85→        Ok(jjrf_Firemark(stripped.to_string()))
    86→    }
    87→
    88→    /// Get the raw base64 string (without prefix)
    89→    pub fn jjrf_as_str(&self) -> &str {
    90→        &self.0
    91→    }
    92→
    93→    /// Format with prefix for display
    94→    pub fn jjrf_display(&self) -> String {
    95→        format!("{}{}", JJRF_FIREMARK_PREFIX, self.0)
    96→    }
    97→}
    98→
    99→impl jjrf_Coronet {
   100→    /// Encode a Heat identity and pace index as a Coronet
   101→    pub fn jjrf_encode(heat: &jjrf_Firemark, pace_index: u32) -> Self {
   102→        debug_assert!(
   103→            pace_index <= JJRF_CORONET_PACE_MAX,
   104→            "Coronet pace index {} exceeds max {}",
   105→            pace_index,
   106→            JJRF_CORONET_PACE_MAX
   107→        );
   108→        let p2 = zjjrf_value_to_char((pace_index / 4096) as u8);
   109→        let p1 = zjjrf_value_to_char(((pace_index / 64) % 64) as u8);
   110→        let p0 = zjjrf_value_to_char((pace_index % 64) as u8);
   111→        jjrf_Coronet(format!("{}{}{}{}", heat.jjrf_as_str(), p2, p1, p0))
   112→    }
   113→
   114→    /// Decode a Coronet to its parent Heat and pace index
   115→    pub fn jjrf_decode(&self) -> Result<(jjrf_Firemark, u32), String> {
   116→        let chars: Vec<char> = self.0.chars().collect();
   117→        if chars.len() != 5 {
   118→            return Err(format!("Coronet must be 5 characters, got {}", chars.len()));
   119→        }
   120→        let heat = jjrf_Firemark(chars[0..2].iter().collect());
   121→        let p2 = zjjrf_char_to_value(chars[2])? as u32;
   122→        let p1 = zjjrf_char_to_value(chars[3])? as u32;
   123→        let p0 = zjjrf_char_to_value(chars[4])? as u32;
   124→        let pace_index = p2 * 4096 + p1 * 64 + p0;
   125→        Ok((heat, pace_index))
   126→    }
   127→
   128→    /// Parse a Coronet from string input (with or without prefix)
   129→    pub fn jjrf_parse(input: &str) -> Result<Self, String> {
   130→        let stripped = input.strip_prefix(JJRF_CORONET_PREFIX).unwrap_or(input);
   131→        if stripped.len() != 5 {
   132→            return Err(format!(
   133→                "Coronet must be 5 base64 characters (with or without {} prefix), got '{}'",
   134→                JJRF_CORONET_PREFIX, input
   135→            ));
   136→        }
   137→        // Validate all characters are in charset
   138→        for c in stripped.chars() {
   139→            zjjrf_char_to_value(c)?;
   140→        }
   141→        Ok(jjrf_Coronet(stripped.to_string()))
   142→    }
   143→
   144→    /// Get the raw base64 string (without prefix)
   145→    pub fn jjrf_as_str(&self) -> &str {
   146→        &self.0
   147→    }
   148→
   149→    /// Format with prefix for display
   150→    pub fn jjrf_display(&self) -> String {
   151→        format!("{}{}", JJRF_CORONET_PREFIX, self.0)
   152→    }
   153→
   154→    /// Extract the parent Firemark (first 2 base64 chars)
   155→    pub fn jjrf_parent_firemark(&self) -> jjrf_Firemark {
   156→        jjrf_Firemark(self.0[..2].to_string())
   157→    }
   158→}
